import aiohttpimport asyncioimport osfrom config import TELEGRAM_TOKEN  # не используется, но оставлено для совместимости# ===== ВАШИ ДАННЫЕ (УЖЕ РАБОТАЮТ) =====FOLDER_ID = "b1gjatvnea5nfs88fncv"YANDEX_API_KEY = os.getenv("YANDEX_API_KEY")YANDEX_GPT_URL = "https://llm.api.cloud.yandex.net/foundationModels/v1/completion"# =======================================async def ask_cloud_model(user_message: str) -> str:    """Отправляет запрос к YandexGPT с улучшенным промптом и возвращает ответ."""    try:        headers = {            "Authorization": f"Api-Key {API_KEY}",            "Content-Type": "application/json"        }        # Улучшенный системный промпт – задаёт чёткую роль стоматолога-эксперта        system_prompt = (            "Ты – опытный стоматолог с 20-летним стажем, работаешь в клинике «Улыбка+». "            "Твоя задача – давать пациентам полезные, точные и понятные ответы о здоровье зубов, гигиене, профилактике и лечении. "            "Отвечай на русском языке, используй дружелюбный, заботливый тон.\n"            "Правила:\n"            "1. Если вопрос касается симптомов (боль, кровоточивость, чувствительность), обязательно подчеркни, что для точного диагноза нужно обратиться к врачу.\n"            "2. Не ставь окончательных диагнозов, не назначай лекарства, не указывай дозировки.\n"            "3. Если вопрос не связан со стоматологией, вежливо сообщи, что это не твоя специализация, и предложи задать вопрос по теме.\n"            "4. Старайся давать развёрнутые, но не перегруженные ответы, приводи примеры, если уместно.\n"            "5. Используй простой язык, избегай излишней научной терминологии без объяснений.\n"            "Будь полезным и заботливым помощником."        )        payload = {            "modelUri": f"gpt://{FOLDER_ID}/yandexgpt-lite",  # можно заменить на yandexgpt для лучшего качества            "completionOptions": {                "stream": False,                "temperature": 0.4,          # снижена для большей фактологичности                "maxTokens": 1200              # увеличено для развёрнутых ответов            },            "messages": [                {"role": "system", "text": system_prompt},                {"role": "user", "text": user_message}            ]        }        async with aiohttp.ClientSession() as session:            async with session.post(YANDEX_GPT_URL, headers=headers, json=payload) as resp:                if resp.status == 200:                    data = await resp.json()                    return data["result"]["alternatives"][0]["message"]["text"]                else:                    text = await resp.text()                    return f"Ошибка {resp.status}: {text}"    except Exception as e:        return f"Ошибка: {e}"